INSERT INTO `wp_posts` VALUES (30,1,'2026-03-09 10:22:04','2026-03-09 09:22:04','<label> Votre nom\r\n    [text* your-name autocomplete:name] </label>\r\n\r\n<label> Votre e-mail\r\n    [email* your-email autocomplete:email] </label>\r\n\r\n<label> Objet\r\n    [text* your-subject] </label>\r\n\r\n<label> Votre message (facultatif)\r\n    [textarea your-message] </label>\r\n\r\n[submit \"Envoyer\"]\n1\n[_site_title] \"[your-subject]\"\n[_site_title] <wordpress@arb-auvergne.local>\n[_site_admin_email]\nDe : [your-name] [your-email]\r\nObjet : [your-subject]\r\n\r\nCorps du message :\r\n[your-message]\r\n\r\n-- \r\nCeci est une notification qu’un formulaire de contact a été envoyé sur votre site web ([_site_title] [_site_url]).\nReply-To: [your-email]\n\n1\n1\n\n[_site_title] \"[your-subject]\"\n[_site_title] <wordpress@arb-auvergne.local>\n[your-email]\nCorps du message :\r\n[your-message]\r\n\r\n-- \r\nCet e-mail est un accusé de réception du formulaire de contact que vous avez envoyé sur notre site web ([_site_title] [_site_url]) et dans lequel votre adresse e-mail a été utilisée. Si ce n’est pas vous, veuillez ignorer ce message.\nReply-To: [_site_admin_email]\n\n1\n1\nMerci pour votre message. Il a été envoyé.\nUne erreur s’est produite lors de l’envoi de votre message. Veuillez essayer à nouveau plus tard.\nUn ou plusieurs champs contiennent une erreur. Veuillez vérifier et essayer à nouveau.\nUne erreur s’est produite lors de l’envoi de votre message. Veuillez essayer à nouveau plus tard.\nVous devez accepter les termes et conditions avant d’envoyer votre message.\nVeuillez renseigner ce champ.\nCe champ a une saisie trop longue.\nCe champ a une saisie trop courte.\nUne erreur inconnue s’est produite lors du téléversement du fichier.\nVous n’avez pas les droits nécessaires pour téléverser ce type de fichier.\nLe fichier téléversé est trop volumineux.\nUne erreur s’est produite lors du téléversement du fichier.\nVeuillez saisir une date au format AAAA-MM-JJ.\nLa date de ce champ est trop tôt.\nLa date de ce champ est trop tardive.\nVeuillez saisir un numéro.\nLe chiffre de ce champ est trop petit.\nCe champ a un numéro trop long.\nLa réponse à la question est incorrecte.\nVeuillez saisir votre adresse e-mail.\nVeuillez saisisr une URL\nVeuillez saisir un numéro de téléphone.','Arbauvergne','','publish','closed','closed','','formulaire-de-contact-1','','','2026-03-09 11:14:01','2026-03-09 10:14:01','',0,'http://arb-auvergne.local/?post_type=wpcf7_contact_form&#038;p=30',0,'wpcf7_contact_form','',0);
